import { useState } from "react";
import { FaEnvelope } from "react-icons/fa"; // Import icons
import { useNavigate } from "react-router-dom";
import axios from "axios"; // Import axios for API requests
import "./forgotpassword.css"; // Import CSS

const ForgotPassword = () => {
  const [email, setEmail] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!email) {
      setError("Email is required!");
      setMessage("");
      return;
    }

    if (!/\S+@\S+\.\S+/.test(email)) {
      setError("Invalid email format!");
      setMessage("");
      return;
    }

    try {
      const response = await axios.post("http://localhost:5000/api/auth/forgot-password", { email });

      setMessage(response.data.message);
      setError("");
    } catch (error) {
      setError(error.response?.data?.message || "Request failed❌");
      setMessage("");
    }
  };

  return (
    <div className="login-container">
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />

      <form onSubmit={handleSubmit} className="login-form">
        <h2>Forgot Password</h2>

        <div className="input-group">
          <FaEnvelope className="icon" />
          <input
            type="email"
            placeholder="Enter your College Mail ID"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>

        <button type="submit" className="login-button">Send OTP</button>

        <div className="forget-password">
          <a href="#" onClick={() => navigate("/")}>Back to Login</a>
        </div>

        <div className="message-container">
          {error && <p className="error-message">{error}</p>}
          {message && <p className="success-message">{message}</p>}
        </div>
      </form>
    </div>
  );
};

export default ForgotPassword;
